14→function PlanViewportContent({ floor }) {
15→  return (
16→    <>
17→      {(floor.slabs || []).map(slab => (
18→        <SlabRenderer key={slab.id} slab={slab} selectedId={null} />
19→      ))}
20→      <RoomRenderer rooms={floor.rooms} selectedId={null} />
21→      <WallRenderer walls={floor.walls} columns={floor.columns || []} />
22→      <BeamRenderer beams={floor.beams || []} columns={floor.columns || []} />
23→      <StairRenderer stairs={floor.stairs || []} />
24→      <ColumnRenderer columns={floor.columns || []} />
25→      <DoorRenderer doors={floor.doors} walls={floor.walls} />
26→      <WindowRenderer windows={floor.windows} walls={floor.walls} />
27→      {(floor.sectionCuts || []).map(sc => (
28→        <SectionCutRenderer key={sc.id} sectionCut={sc} selectedId={null} />
29→      ))}
30→      <AnnotationRenderer floor={floor} />
31→    </>
32→  );
33→}
