  1→import { buildSheetScene } from '@/sheets/layout';
  2→import { getViewportHandleRects, getViewportRotationHandle } from '@/sheets/hitTest';
  3→import SheetViewportContent from './SheetViewportContent';
  4→
  5→const HANDLE_SIZE = 4;
