  7→function TitleBlock({ titleBlock }) {
  8→  const rowHeight = titleBlock.height / titleBlock.rows.length;
  9→
 10→  return (
 11→    <g className="sheet-title-block">
 12→      <rect
 13→        x={titleBlock.x}
 14→        y={titleBlock.y}
 15→        width={titleBlock.width}
 16→        height={titleBlock.height}
 17→        fill="#ffffff"
 18→        stroke="#4c5b70"
 19→        strokeWidth={0.5}
 20→      />
 21→      {titleBlock.rows.map((row, index) => {
 22→        const y = titleBlock.y + rowHeight * index;
 23→        return (
 24→          <g key={row.label}>
 25→            <line
 26→              x1={titleBlock.x}
 27→              y1={y}
 28→              x2={titleBlock.x + titleBlock.width}
 29→              y2={y}
 30→              stroke="#4c5b70"
 31→              strokeWidth={0.35}
 32→            />
 33→            <line
 34→              x1={titleBlock.x + titleBlock.width * 0.28}
 35→              y1={y}
 36→              x2={titleBlock.x + titleBlock.width * 0.28}
 37→              y2={y + rowHeight}
 38→              stroke="#4c5b70"
 39→              strokeWidth={0.35}
 40→            />
 41→            <text x={titleBlock.x + 2} y={y + rowHeight * 0.67} fontSize={2.5} fill="#4c5b70">
 42→              {row.label}
 43→            </text>
 44→            <text x={titleBlock.x + titleBlock.width * 0.31} y={y + rowHeight * 0.67} fontSize={2.8} fill="#223247">
 45→              {row.value}
 46→            </text>
 47→          </g>
 48→        );
 49→      })}
 50→    </g>
 51→  );
 52→}
