 1→import BlueprintAnnotationLayer from './BlueprintAnnotationLayer';
 2→
 3→const STYLE_MAP = {
 4→  wall: { fill: '#f7f8fa', stroke: '#4c5b70' },
 5→  slab: { fill: '#d7dee8', stroke: '#4c5b70' },
 6→  column: { fill: '#c2c8cf', stroke: '#4c5b70' },
 7→  beam: { fill: '#b3c0cf', stroke: '#4c5b70' },
 8→  stair: { fill: '#e4e8ef', stroke: '#4c5b70' },
 9→  door: { fill: '#ffffff', stroke: '#4c5b70' },
10→  window: { fill: '#e6f3ff', stroke: '#4c5b70' },
11→};
12→
13→function rectPoints(element) {
14→  return [
15→    `${element.left},${-element.top}`,
16→    `${element.right},${-element.top}`,
17→    `${element.right},${-element.bottom}`,
18→    `${element.left},${-element.bottom}`,
19→  ].join(' ');
20→}
21→
22→export default function ElevationSceneLayer({ scene, annotationScene, showTitle = true, selectedId = null, selectedType = null }) {
23→  if (!scene) return null;
24→
25→  const titleX = (scene.bounds.minX + scene.bounds.maxX) / 2;
26→  const titleY = -scene.bounds.maxZ - 500;
27→
28→  return (
29→    <g className="elevation">
30→      {showTitle && (
31→        <text
32→          x={titleX}
33→          y={titleY}
34→          textAnchor="middle"
35→          dominantBaseline="middle"
36→          fill="var(--color-text-secondary)"
37→          fontSize={220}
38→          fontFamily="var(--font-blueprint)"
39→          style={{ pointerEvents: 'none' }}
40→        >
41→          {scene.title}
42→        </text>
43→      )}
44→      {scene.elements.map((element) => {
45→        const style = STYLE_MAP[element.style] || STYLE_MAP.wall;
46→        const isSelected = element.category === selectedType && element.sourceId === selectedId;
47→        return (
48→          <polygon
49→            key={element.id}
50→            points={rectPoints(element)}
51→            fill={style.fill}
52→            stroke={isSelected ? 'var(--color-selection)' : style.stroke}
53→            strokeWidth={isSelected ? 2 : 1}
54→            vectorEffect="non-scaling-stroke"
55→            opacity={isSelected ? 0.95 : 1}
56→          />
57→        );
58→      })}
59→      <line
60→        x1={scene.bounds.minX - 500}
61→        y1={-scene.groundLevel}
62→        x2={scene.bounds.maxX + 500}
63→        y2={-scene.groundLevel}
64→        stroke="var(--color-text-secondary)"
65→        strokeWidth={1}
66→        strokeDasharray="10 6"
67→        vectorEffect="non-scaling-stroke"
68→        opacity={0.6}
69→      />
70→      {annotationScene && (
71→        <BlueprintAnnotationLayer
72→          className="elevation-annotations"
73→          dimensions={annotationScene.dimensions}
74→        />
75→      )}
76→    </g>
77→  );
78→}
