 1→import { buildProjectSectionScene } from '@/sections/scene';
 2→import SectionSceneLayer from './SectionSceneLayer';
 3→
 4→export default function SectionRenderer({ project, floor, activeSectionCutId }) {
 5→  const cuts = floor?.sectionCuts || [];
 6→  const sectionCut = (activeSectionCutId && cuts.find(s => s.id === activeSectionCutId)) || cuts[0] || null;
 7→
 8→  if (!sectionCut) {
 9→    return (
10→      <g className="section-empty">
11→        <text
12→          x={0}
13→          y={0}
14→          textAnchor="middle"
15→          dominantBaseline="middle"
16→          fill="var(--color-text-secondary)"
17→          fontSize={180}
18→          fontFamily="var(--font-blueprint)"
19→        >
20→          Draw a section cut in plan view.
21→        </text>
22→      </g>
23→    );
24→  }
25→
26→  const scene = buildProjectSectionScene(project, floor.id, sectionCut.id);
27→  if (!scene) return null;
28→
29→  return <SectionSceneLayer scene={scene} />;
30→}
