 1→const STYLE_MAP = {
 2→  wall_cut: { fill: '#cfd7e3', stroke: '#35465d', strokeWidth: 1.8, opacity: 1 },
 3→  wall_projection: { fill: '#f7f8fa', stroke: '#7d8ca0', strokeWidth: 1, opacity: 0.7 },
 4→  slab_cut: { fill: '#bcc7d6', stroke: '#35465d', strokeWidth: 1.8, opacity: 1 },
 5→  slab_projection: { fill: '#dfe6ef', stroke: '#7d8ca0', strokeWidth: 1, opacity: 0.7 },
 6→  column_cut: { fill: '#b9c1cb', stroke: '#35465d', strokeWidth: 1.8, opacity: 1 },
 7→  column_projection: { fill: '#d7dde5', stroke: '#7d8ca0', strokeWidth: 1, opacity: 0.7 },
 8→  beam_cut: { fill: '#b4c1d0', stroke: '#35465d', strokeWidth: 1.8, opacity: 1 },
 9→  beam_projection: { fill: '#d8e0ea', stroke: '#7d8ca0', strokeWidth: 1, opacity: 0.7 },
10→  door_cut: { fill: '#ffffff', stroke: '#35465d', strokeWidth: 1.5, opacity: 1 },
