 85→function buildPlanSource(floor) {
 86→  if (!floor) {
 87→    return {
 88→      kind: 'empty',
 89→      title: 'Plan',
 90→      message: 'Missing floor.',
 91→      bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1500 },
 92→    };
 93→  }
 94→
 95→  const geometryBounds = expandBounds(boundsFromPoints(collectPlanPoints(floor)), PLAN_PADDING);
 96→
 97→  return {
 98→    kind: 'plan',
 99→    title: `${floor.name} Plan`,
100→    floor,
101→    bounds: geometryBounds,
102→  };
103→}
104→
105→function sceneBoundsToRenderBounds(scene) {
106→  return {
107→    minX: scene.bounds.minX - VERTICAL_PADDING,
108→    maxX: scene.bounds.maxX + VERTICAL_PADDING,
109→    minY: -scene.bounds.maxZ - TOP_PADDING,
110→    maxY: -scene.bounds.minZ + VERTICAL_PADDING,
111→  };
112→}
113→
114→function buildSectionSource(project, floor, sourceRefId) {
115→  const cuts = floor?.sectionCuts || [];
116→  const sectionCut = sourceRefId
117→    ? cuts.find(s => s.id === sourceRefId)
118→    : cuts[0] || null;
119→
120→  if (!sectionCut) {
121→    return {
122→      kind: 'empty',
123→      title: 'Section',
124→      message: 'No section cut on this floor.',
125→      bounds: { minX: 0, maxX: 2000, minY: -3000, maxY: 1000 },
126→    };
127→  }
128→
129→  const scene = buildProjectSectionScene(project, floor.id, sectionCut.id);
130→  return {
131→    kind: 'section',
132→    title: sectionCut.label || 'Section',
133→    floor,
134→    scene,
135→    bounds: sceneBoundsToRenderBounds(scene),
136→  };
137→}
138→
139→function buildElevationSource(project, floor, sourceView) {
140→  if (!floor) {
141→    return {
142→      kind: 'empty',
143→      title: 'Elevation',
144→      message: 'Missing floor.',
145→      bounds: { minX: 0, maxX: 2000, minY: -3000, maxY: 1000 },
146→    };
147→  }
148→
149→  const scene = buildProjectElevationScene(project, floor.id, sourceView);
150→  const annotationScene = buildElevationAnnotationScene(floor, scene);
151→
152→  return {
153→    kind: 'elevation',
154→    title: scene.title,
155→    floor,
156→    viewMode: sourceView,
157→    scene,
158→    annotationScene,
159→    bounds: sceneBoundsToRenderBounds(scene),
160→  };
161→}
