181→export function getViewportSourceLabel(sourceView) {
182→  switch (sourceView) {
183→    case 'section':
184→      return 'Section';
185→    case 'elevation_front':
186→      return 'Front Elevation';
187→    case 'elevation_rear':
188→      return 'Rear Elevation';
189→    case 'elevation_left':
190→      return 'Left Elevation';
191→    case 'elevation_right':
192→      return 'Right Elevation';
193→    case 'plan':
194→    default:
195→      return 'Plan';
196→  }
197→}
