  4→
  5→const SHEET_MARGIN = 12;
  6→const TITLE_BLOCK_HEIGHT = 32;
  7→const CONTENT_PADDING = 4;
  8→
  9→function clamp(value, min, max) {
 10→  return Math.max(min, Math.min(max, value));
 11→}
 12→
 13→function resolveViewportScale(viewport) {
 14→  return Math.max(1, viewport.scale || 100);
 15→}
 16→
 17→function buildTitleBlock(project, sheet, paper) {
 18→  const titleBlockWidth = Math.min(130, paper.width * 0.42);
 19→  const x = paper.width - SHEET_MARGIN - titleBlockWidth;
 20→  const y = paper.height - SHEET_MARGIN - TITLE_BLOCK_HEIGHT;
 21→
 22→  return {
 23→    x,
 24→    y,
 25→    width: titleBlockWidth,
 26→    height: TITLE_BLOCK_HEIGHT,
 27→    rows: [
 28→      { label: 'Drawing', value: sheet.drawingName || getSheetDisplayLabel(sheet) },
 29→      { label: 'Project', value: sheet.projectNameOverride || project.name || 'Untitled Project' },
 30→      { label: 'Scale', value: sheet.scaleLabel || 'As noted' },
 31→    ],
 32→  };
 33→}
 34→
 35→function resolveViewportTitle(viewport, source) {
 36→  return viewport.title?.trim() || source.title || getViewportSourceLabel(viewport.sourceView);
 37→}
 38→
 39→function buildViewportFrame(viewport, source) {
 40→  const bounds = source.bounds || { minX: 0, maxX: 1000, minY: 0, maxY: 1000 };
 41→  const scale = 1 / resolveViewportScale(viewport);
 42→  const sourceWidth = Math.max(1, bounds.maxX - bounds.minX);
 43→  const sourceHeight = Math.max(1, bounds.maxY - bounds.minY);
 44→  const innerWidth = Math.max(10, viewport.width - CONTENT_PADDING * 2);
 45→  const innerHeight = Math.max(10, viewport.height - CONTENT_PADDING * 2);
 46→  const drawnWidth = sourceWidth * scale;
 47→  const drawnHeight = sourceHeight * scale;
 48→
 49→  const translateX = Math.max(0, (innerWidth - drawnWidth) / 2) - bounds.minX * scale;
 50→  const translateY = Math.max(0, (innerHeight - drawnHeight) / 2) - bounds.minY * scale;
 51→
 52→  return {
 53→    ...viewport,
 54→    rotation: viewport.rotation || 0,
 55→    title: resolveViewportTitle(viewport, source),
 56→    source,
 57→    clipRect: {
 58→      x: viewport.x + CONTENT_PADDING,
 59→      y: viewport.y + CONTENT_PADDING,
 60→      width: innerWidth,
 61→      height: innerHeight,
 62→    },
 63→    contentTransform: {
 64→      translateX,
 65→      translateY,
 66→      scale,
 67→    },
 68→  };
 69→}
